using System;
using UnityEngine;
using UnityEngine.InputSystem;

[RequireComponent(typeof(PlayerInput))]
public class PlayerInputRouter : MonoBehaviour
{
    public enum InputMode
    {
        Gameplay,
        ItemWheel,
        FormWheel
    }

    [Header("Item navigation (Gameplay only)")]
    [SerializeField] private float itemNavDeadzone = 0.6f;
    [SerializeField] private float itemNavCooldown = 0.25f;

    public InputMode Mode { get; private set; } = InputMode.Gameplay;

    public Vector2 Move { get; private set; }
    public Vector2 Look { get; private set; }

    public bool AbilityHeld => _ability != null && _ability.IsPressed();

    // Basic actions
    public event Action JumpPressed;
    public event Action JumpReleased;
    public event Action AttackPressed;

    // Interagir: usado para diálogo com NPCs E (P4/P6 — REFORMULADO) para
    // agarrar objectos/cordas/escadas/empurráveis. InteractPressed dispara no
    // toque (diálogo, cipós/escadas — "apertar enquanto estiver nele");
    // InteractHeld fica true enquanto o botão está premido (agarrar objectos
    // ao toque, escalar paredes com 'cima', puxar blocos); InteractReleased
    // dispara ao soltar.
    public event Action InteractPressed;
    public event Action InteractReleased;

    public bool InteractHeld => _interact != null && _interact.IsPressed();

    /// <summary>
    /// Mitigação do conflito "um só toque activa mais de uma coisa" (pedido
    /// "InteractionManager"): vários sistemas independentes (diálogo,
    /// cordas/escadas/cipós, agarrar, SafeHaven, etc.) escutam
    /// <see cref="InteractPressed"/>. É reposto a false ANTES de
    /// InteractPressed disparar; o primeiro handler que decidir agir marca-o
    /// a true para impedir que os handlers seguintes (chamados na mesma
    /// invocação, por ordem de subscrição) também actuem nesse toque.
    /// Não substitui um InteractionManager completo, mas resolve o caso
    /// comum sem reescrever os sistemas existentes.
    /// </summary>
    public bool InteractConsumed { get; set; }

    // Ability (ZR)
    public event Action AbilityPressed;
    public event Action AbilityReleased;

    // Forms
    public event Action PrevFormTapped;
    public event Action NextFormTapped;
    public event Action FormWheelOpened;
    public event Action FormWheelClosed;
    public event Action ConfirmTransformHold; // dispara quando o hold completa

    // Items
    public event Action UseItemHold;          // dispara quando o hold completa
    public event Action ItemWheelPressed;     // abre/fecha a roda (tu decides no controller)
    public event Action ItemNext;
    public event Action ItemPrev;

    // UI
    public event Action PausePressed;

    /// <summary>Abre o Menu Secundário ("-" no gamepad) — Upgrades e futuras abas.</summary>
    public event Action SecondaryMenuPressed;

    /// <summary>Reservado para o Mapa-Múndi (hub de mundos/áreas) — não existe "mapa local" no jogo.</summary>
    public event Action MapPressed;

    private PlayerInput _playerInput;

    private InputAction _move;
    private InputAction _look;

    private InputAction _jump;
    private InputAction _attack;
    private InputAction _interact;

    private InputAction _ability;

    private InputAction _prevForm;
    private InputAction _nextForm;
    private InputAction _formWheel;
    private InputAction _confirmTransform;

    private InputAction _useItem;
    private InputAction _itemWheel;
    private InputAction _pause;
    private InputAction _secondaryMenu;
    private InputAction _map;

    private InputAction[] _allActions;

    private float _nextItemNavTime;

    /// <summary>
    /// Define como o Router deve interpretar inputs (Gameplay vs rodas).
    /// Quando est� em ItemWheel ou FormWheel, a navega��o ItemNext/Prev fica bloqueada.
    /// </summary>
    public void SetMode(InputMode mode)
    {
        Mode = mode;

        // Opcional: reseta cooldown para evitar disparo "fantasma" ao fechar a roda.
        _nextItemNavTime = Time.time + 0.05f;
    }

    private void Awake()
    {
        _playerInput = GetComponent<PlayerInput>();
        var a = _playerInput.actions;

        // IMPORTANT: os nomes aqui precisam bater com o teu InputActions
        _move = a["Move"];
        _look = a["Look"];

        _jump = a["Jump"];
        _attack = a["Attack"];
        _interact = a["Interact"];

        _ability = a["Ability"];

        _prevForm = a["PrevForm"];
        _nextForm = a["NextForm"];
        _formWheel = a["FormWheel"];
        _confirmTransform = a["ConfirmTransform"];

        _useItem = a["UseItem"];
        _itemWheel = a["ItemWheel"];
        _pause = a["Pause"];
        _secondaryMenu = a["SecondaryMenu"];
        _map = a["Map"];

        _allActions = new[]
        {
            _move, _look, _jump, _attack, _interact, _ability,
            _prevForm, _nextForm, _formWheel, _confirmTransform,
            _useItem, _itemWheel, _pause, _secondaryMenu, _map
        };
    }

    private void OnEnable()
    {
        _move.performed += OnMove;
        _move.canceled += OnMove;

        _look.performed += OnLook;
        _look.canceled += OnLook;

        _jump.performed += OnJumpPerformed;
        _jump.canceled += OnJumpCanceled;
        _attack.performed += OnAttackPerformed;
        _interact.performed += OnInteractPerformed;
        _interact.canceled += OnInteractCanceled;

        _ability.started += OnAbilityStarted;
        _ability.canceled += OnAbilityCanceled;

        _prevForm.performed += OnPrevFormPerformed;
        _nextForm.performed += OnNextFormPerformed;

        // Hold actions: performed s� dispara quando completou o tempo
        _formWheel.performed += OnFormWheelPerformed;

        // canceled dispara quando solta o bot�o (mesmo que n�o tenha completado hold)
        _formWheel.canceled += OnFormWheelCanceled;

        _confirmTransform.performed += OnConfirmTransformPerformed;

        _useItem.performed += OnUseItemPerformed;

        _itemWheel.performed += OnItemWheelPerformed;

        _pause.performed += OnPausePerformed;
        _secondaryMenu.performed += OnSecondaryMenuPerformed;
        _map.performed += OnMapPerformed;

        EnableAll();
    }

    private void OnDisable()
    {
        _move.performed -= OnMove;
        _move.canceled -= OnMove;

        _look.performed -= OnLook;
        _look.canceled -= OnLook;

        _jump.performed -= OnJumpPerformed;
        _jump.canceled -= OnJumpCanceled;
        _attack.performed -= OnAttackPerformed;
        _interact.performed -= OnInteractPerformed;
        _interact.canceled -= OnInteractCanceled;

        _ability.started -= OnAbilityStarted;
        _ability.canceled -= OnAbilityCanceled;

        _prevForm.performed -= OnPrevFormPerformed;
        _nextForm.performed -= OnNextFormPerformed;

        _formWheel.performed -= OnFormWheelPerformed;
        _formWheel.canceled -= OnFormWheelCanceled;

        _confirmTransform.performed -= OnConfirmTransformPerformed;

        _useItem.performed -= OnUseItemPerformed;

        _itemWheel.performed -= OnItemWheelPerformed;

        _pause.performed -= OnPausePerformed;
        _secondaryMenu.performed -= OnSecondaryMenuPerformed;
        _map.performed -= OnMapPerformed;

        DisableAll();
    }

    // --- Handlers nomeados (necess�rio para poder desinscrever em OnDisable e
    // evitar callbacks duplicados a cada ciclo de enable/disable) ---

    private void OnJumpPerformed(InputAction.CallbackContext ctx) => JumpPressed?.Invoke();
    private void OnJumpCanceled(InputAction.CallbackContext ctx) => JumpReleased?.Invoke();
    private void OnAttackPerformed(InputAction.CallbackContext ctx) => AttackPressed?.Invoke();

    private void OnInteractPerformed(InputAction.CallbackContext ctx)
    {
        InteractConsumed = false;
        InteractPressed?.Invoke();
    }

    private void OnInteractCanceled(InputAction.CallbackContext ctx) => InteractReleased?.Invoke();

    private void OnAbilityStarted(InputAction.CallbackContext ctx) => AbilityPressed?.Invoke();
    private void OnAbilityCanceled(InputAction.CallbackContext ctx) => AbilityReleased?.Invoke();

    private void OnPrevFormPerformed(InputAction.CallbackContext ctx) => PrevFormTapped?.Invoke();
    private void OnNextFormPerformed(InputAction.CallbackContext ctx) => NextFormTapped?.Invoke();

    private void OnFormWheelPerformed(InputAction.CallbackContext ctx)
    {
        SetMode(InputMode.FormWheel);
        FormWheelOpened?.Invoke();
    }

    private void OnFormWheelCanceled(InputAction.CallbackContext ctx)
    {
        // Só restaura Gameplay se o modo actual for FormWheel — evita sobrescrever
        // ItemWheel caso este esteja aberto ao mesmo tempo (edge case com dois dedos).
        if (Mode == InputMode.FormWheel)
            SetMode(InputMode.Gameplay);

        FormWheelClosed?.Invoke();
    }

    private void OnConfirmTransformPerformed(InputAction.CallbackContext ctx) => ConfirmTransformHold?.Invoke();
    private void OnUseItemPerformed(InputAction.CallbackContext ctx) => UseItemHold?.Invoke();

    private void OnItemWheelPerformed(InputAction.CallbackContext ctx)
    {
        // Router n�o decide abrir/fechar UI, s� avisa.
        // O teu ItemWheelController deve alternar e chamar SetMode(ItemWheel ou Gameplay).
        ItemWheelPressed?.Invoke();
    }

    private void OnPausePerformed(InputAction.CallbackContext ctx) => PausePressed?.Invoke();
    private void OnSecondaryMenuPerformed(InputAction.CallbackContext ctx) => SecondaryMenuPressed?.Invoke();
    private void OnMapPerformed(InputAction.CallbackContext ctx) => MapPressed?.Invoke();

    private void Update()
    {
        // Navega itens com stick direito no modo Gameplay (troca rápida do
        // item equipado) E no modo ItemWheel (navegação dentro da Roda de
        // Itens — ver ItemWheelUI). Bloqueado apenas com a Roda de Formas
        // aberta, para não trocar de item por engano enquanto se escolhe forma.
        if (Mode == InputMode.FormWheel) return;

        if (Time.time < _nextItemNavTime) return;

        float x = Look.x;

        if (x > itemNavDeadzone)
        {
            _nextItemNavTime = Time.time + itemNavCooldown;
            ItemNext?.Invoke();
        }
        else if (x < -itemNavDeadzone)
        {
            _nextItemNavTime = Time.time + itemNavCooldown;
            ItemPrev?.Invoke();
        }
    }

    private void OnMove(InputAction.CallbackContext ctx)
    {
        Move = ctx.ReadValue<Vector2>();
    }

    private void OnLook(InputAction.CallbackContext ctx)
    {
        Look = ctx.ReadValue<Vector2>();
    }

    private void EnableAll()
    {
        foreach (var action in _allActions)
            action.Enable();
    }

    private void DisableAll()
    {
        foreach (var action in _allActions)
            action.Disable();
    }
}
